  90	} from '../constants';
  91	import { CreateStoragePoolModal } from '../modals/storage-pool/create-storage-pool-modal';
  92	import { CephFilesystemKind, StoragePool, StoragePoolKind } from '../types';
  93	import '../style.scss';
  94	import './sc-form.scss';
  95	import {
  96	  getExistingBlockPoolNames,
  97	  getExistingFsPoolNames,
  98	  getStoragePoolsFromBlockPools,
  99	  getStoragePoolsFromFilesystem,
 100	} from '../utils';
 101	
 102	type OnParamChange = (id: string, paramName: string, checkbox: boolean) => void;
 103	
 104	const storageClusterResource: WatchK8sResource = {
 105	  kind: referenceForModel(StorageClusterModel),
 106	  isList: true,
 107	};
 108	
 109	const filterOCSStorageSystems = (resource) => isOCSStorageSystem(resource);
 110	
 111	const setSessionStorageSystemNamespace = (systemNamespace: string) => {
 112	  // session value will get removed after clicking "Create" (check "mutators.ts"),
 113	  // so in case of any error (after clicking "Create") form persists but session gets removed.
 114	  const sessionNsValue = sessionStorage.getItem(CEPH_NS_SESSION_STORAGE);
 115	  if (!sessionNsValue && !!systemNamespace)
 116	    sessionStorage.setItem(CEPH_NS_SESSION_STORAGE, systemNamespace);
 117	};
 118	
 119	const getPoolDropdownItems = (
 120	  poolData: StoragePool[],
 121	  cephCluster,
 122	  handleDropdownChange,
 123	  onPoolCreation,
 124	  launchModal,
 125	  t,
 126	  defaultDeviceClass: string,
 127	  poolType: PoolType,
 128	  existingNames: string[],
 129	  filesystemName = ''
 130	) =>
 131	  _.reduce(
 132	    poolData,
 133	    (res, pool: StoragePool) => {
 134	      const compressionMode = pool?.spec?.compressionMode;
 135	      const isCompressionEnabled: boolean =
 136	        !!compressionMode && compressionMode !== 'none';
 137	      const compressionText = !isCompressionEnabled
 138	        ? t('no compression')
 139	        : t('with compression');
 140	      if (
 141	        pool?.status?.phase === PoolState.READY &&
 142	        cephCluster?.status?.phase === ClusterStatus.READY
 143	      ) {
 144	        res.push(
 145	          <DropdownItem
 146	            key={pool?.metadata?.name}
 147	            component="button"
 148	            id={pool?.metadata?.name}
 149	            data-test={pool?.metadata?.name}
 150	            onClick={handleDropdownChange}
 151	            description={t('Replica {{poolSize}} {{compressionText}}', {
 152	              poolSize: pool?.spec?.replicated?.size,
 153	              compressionText,
 154	            })}
 155	          >
 156	            {pool?.metadata?.name}
 157	          </DropdownItem>
 158	        );
 159	      }
 160	      return res;
 161	    },
 162	    [
 163	      <DropdownItem
 164	        data-test="create-new-pool-button"
 165	        key="first-item"
 166	        component="button"
 167	        onClick={() =>
 168	          launchModal(CreateStoragePoolModal, {
 169	            cephCluster,
 170	            onPoolCreation,
 171	            defaultDeviceClass,
 172	            poolType,
 173	            existingNames,
 174	            filesystemName,
 175	          })
 176	        }
 177	      >
 178	        <span className="ocs-storage-class__pool--create">
 179	          <AddCircleOIcon className="pf-v6-u-mr-sm" />
 180	          {t('Create new storage pool')}
 181	        </span>
 182	      </DropdownItem>,
 183	      <Divider key="separator" />,
 184	    ]
 185	  );
 186	
 187	const StorageSystemDropdown: React.FC<{
 188	  onSelect: (resource: K8sResourceKind) => void;
 189	  systemNamespace: string;
 190	}> = ({ onSelect, systemNamespace }) => {
 191	  const { t } = useCustomTranslation();
 192	
 193	  const initialSSSelection = React.useCallback(
 194	    (resources) => {
 195	      return !systemNamespace
 196	        ? resources?.[0]
 197	        : resources?.find((system) => getNamespace(system) === systemNamespace);
 198	    },
 199	    [systemNamespace]
 200	  );
 201	
 202	  return (
 203	    <div className="form-group">
 204	      <label htmlFor="system-name" className="co-required">
 205	        {t('Storage system')}
 206	      </label>
 207	      <ResourceDropdown<K8sResourceKind>
 208	        className="pf-v5-c-dropdown dropdown--full-width"
 209	        onSelect={onSelect}
 210	        initialSelection={initialSSSelection}
 211	        filterResource={filterOCSStorageSystems}
 212	        id="system-name"
 213	        data-test="storage-system-dropdown"
 214	        resource={storageClusterResource}
 215	        resourceModel={ODFStorageSystem}
 216	      />
 217	      <span className="help-block">
 218	        {t('Select a storage system for your workloads.')}
 219	      </span>
 220	    </div>
 221	  );
 222	};
