 224	export const CephFsNameComponent: React.FC<ProvisionerProps> = ({
 225	  parameterKey,
 226	  parameterValue,
 227	  onParamChange,
 228	}) => {
 229	  const { t } = useCustomTranslation();
 230	  const [systemNamespace, setSystemNamespace] = React.useState<string>();
 231	  const onParamChangeRef = React.useRef<OnParamChange>();
 232	  // reference of "onParamChange" changes on each re-render, hence storing in a "useRef"
 233	  onParamChangeRef.current = onParamChange;
 234	
 235	  const { systemFlags, areFlagsLoaded, flagsLoadError } =
 236	    useODFSystemFlagsSelector();
 237	  const isExternal = systemFlags[systemNamespace]?.isExternalMode;
 238	  const ocsName = systemFlags[systemNamespace]?.ocsClusterName;
 239	  const scName = `${ocsName}-cephfs`;
 240	
 241	  const [sces, scLoaded, scLoadError] =
 242	    useK8sList<StorageClassResourceKind>(StorageClassModel);
 243	  const sc = sces?.find((item) => getName(item) === scName);
 244	
 245	  React.useEffect(() => {
 246	    if (!!sc && scLoaded && !scLoadError) {
 247	      // Get the default filesystem name from StorageClass.
 248	      const fsName = sc?.parameters?.fsName;
 249	      if (fsName) {
 250	        onParamChangeRef.current(parameterKey, fsName, false);
 251	      }
 252	    }
 253	
 254	    return () => onParamChangeRef.current(parameterKey, '', false);
 255	  }, [sc, scLoaded, scLoadError, parameterKey]);
 256	
 257	  const onSelect = React.useCallback(
 258	    (resource: K8sResourceKind) => {
 259	      const ns = getNamespace(resource);
 260	      sessionStorage.setItem(CEPH_NS_SESSION_STORAGE, ns);
 261	      setSystemNamespace(ns);
 262	    },
 263	    [setSystemNamespace]
 264	  );
 265	
 266	  setSessionStorageSystemNamespace(systemNamespace);
 267	
 268	  if (scLoaded && areFlagsLoaded && !scLoadError && !flagsLoadError) {
 269	    return (
 270	      <>
 271	        <StorageSystemDropdown
 272	          onSelect={onSelect}
 273	          systemNamespace={systemNamespace}
 274	        />
 275	        <div className="form-group">
 276	          <label htmlFor="filesystem-name" className="co-required">
 277	            {t('Filesystem name')}
 278	          </label>
 279	          <input
 280	            className="pf-v6-c-form-control"
 281	            type="text"
 282	            value={parameterValue}
 283	            disabled={!isExternal}
 284	            onChange={(e) => {
 285	              onParamChange(parameterKey, e.currentTarget.value, false);
 286	            }}
 287	            placeholder={t('Enter filesystem name')}
 288	            id="filesystem-name"
 289	            required
 290	          />
 291	          <span className="help-block">
 292	            {t('CephFS filesystem name into which the volume shall be created')}
 293	          </span>
 294	        </div>
 295	      </>
 296	    );
 297	  }
 298	  return (
 299	    <StatusBox
 300	      loadError={scLoadError || flagsLoadError}
 301	      loaded={scLoaded && areFlagsLoaded}
 302	    />
 303	  );
 304	};
