 306	export const CephFsPoolComponent: React.FC<ProvisionerProps> = ({
 307	  parameterKey,
 308	  parameterValue,
 309	  onParamChange,
 310	}) => {
 311	  const { t } = useCustomTranslation();
 312	  const onParamChangeRef = React.useRef<OnParamChange>();
 313	  // reference of "onParamChange" changes on each re-render, hence storing in a "useRef"
 314	  onParamChangeRef.current = onParamChange;
 315	
 316	  const launchModal = useModal();
 317	
 318	  const [isOpen, setOpen] = React.useState(false);
 319	
 320	  const [cephClusters, cephClustersLoaded, cephClustersLoadError] =
 321	    useK8sWatchResource<CephClusterKind[]>(cephClusterResource);
 322	
 323	  const { systemFlags, areFlagsLoaded, flagsLoadError, areFlagsSafe } =
 324	    useODFSystemFlagsSelector();
 325	
 326	  const systemNamespace = sessionStorage.getItem(CEPH_NS_SESSION_STORAGE);
 327	  const filesystemName = `${systemFlags[systemNamespace]?.ocsClusterName}-cephfilesystem`;
 328	
 329	  // We read pools from CephFilesystem as it's the only resource where the default pool appears
 330	  // (unlike in StorageCluster CR).
 331	  const [fsData, fsDataLoaded, fsDataLoadError] =
 332	    useK8sWatchResource<CephFilesystemKind>({
 333	      kind: referenceForModel(CephFileSystemModel),
 334	      isList: false,
 335	      name: filesystemName,
 336	      namespace: systemNamespace,
 337	    });
 338	
 339	  const cephCluster = getResourceInNs(cephClusters, systemNamespace);
 340	
 341	  const isExternal = systemFlags[systemNamespace]?.isExternalMode;
 342	
 343	  const isLoaded = areFlagsLoaded && cephClustersLoaded;
 344	  const loadError = flagsLoadError || cephClustersLoadError;
 345	
 346	  const handleDropdownChange = (e: React.KeyboardEvent<HTMLInputElement>) => {
 347	    onParamChange(parameterKey, e.currentTarget.id, false);
 348	  };
 349	
 350	  const onPoolCreation = (name: string) => {
 351	    onParamChange(parameterKey, name, false);
 352	  };
 353	  const onPoolInput = (e: React.ChangeEvent<HTMLInputElement>) => {
 354	    onParamChange(parameterKey, e.currentTarget.value, false);
 355	  };
 356	
 357	  // Collect existing pool names to check against new pool name.
 358	  const poolData = getStoragePoolsFromFilesystem(fsData) || [];
 359	  const existingNames = getExistingFsPoolNames(fsData);
 360	
 361	  const poolToggle = (toggleRef: React.Ref<MenuToggleElement>) => (
 362	    <MenuToggle
 363	      ref={toggleRef}
 364	      id="pool-dropdown-id"
 365	      data-test="pool-dropdown-toggle"
 366	      onClick={() => setOpen(!isOpen)}
 367	      isExpanded={isOpen}
 368	      isFullWidth
 369	    >
 370	      {parameterValue || t('Select a Pool')}
 371	    </MenuToggle>
 372	  );
 373	
 374	  if (areFlagsSafe && isLoaded && !loadError) {
 375	    if (!isExternal && fsDataLoaded && !fsDataLoadError) {
 376	      return (
 377	        <div className="form-group">
 378	          <label className="co-required" htmlFor="ocs-storage-pool">
 379	            {t('Storage Pool')}
 380	          </label>
 381	          <Dropdown
 382	            isOpen={isOpen}
 383	            onSelect={() => setOpen(false)}
 384	            onOpenChange={(open: boolean) => setOpen(open)}
 385	            toggle={poolToggle}
 386	            popperProps={{ width: 'trigger' }}
 387	          >
 388	            <DropdownList>
 389	              {getPoolDropdownItems(
 390	                poolData,
 391	                cephCluster,
 392	                handleDropdownChange,
 393	                onPoolCreation,
 394	                launchModal,
 395	                t,
 396	                '',
 397	                PoolType.FILESYSTEM,
 398	                existingNames,
 399	                filesystemName
 400	              )}
 401	            </DropdownList>
 402	          </Dropdown>
 403	          <span className="help-block">
 404	            {t('Storage pool into which volume data shall be stored')}
 405	          </span>
 406	        </div>
 407	      );
 408	    }
 409	    if (isExternal) {
 410	      return (
 411	        <div className="form-group">
 412	          <label className="co-required" htmlFor="pool-name">
 413	            {t('Storage Pool')}
 414	          </label>
 415	          <input
 416	            className="pf-v6-c-form-control"
 417	            type="text"
 418	            onChange={onPoolInput}
 419	            value={parameterValue}
 420	            placeholder={t('my-storage-pool')}
 421	            aria-describedby={t('pool-name-help')}
 422	            id="pool-name"
 423	            name="newPoolName"
 424	            required
 425	          />
 426	          <span className="help-block">
 427	            {t('Storage pool into which volume data shall be stored')}
 428	          </span>
 429	        </div>
 430	      );
 431	    }
 432	  }
 433	  return (
 434	    <StatusBox
 435	      loaded={isLoaded && fsDataLoaded}
 436	      loadError={loadError || fsDataLoadError}
 437	    />
 438	  );
 439	};
