 441	export const BlockPoolResourceComponent: React.FC<ProvisionerProps> = ({
 442	  parameterKey,
 443	  onParamChange,
 444	}) => {
 445	  const { t } = useCustomTranslation();
 446	  const onParamChangeRef = React.useRef<OnParamChange>();
 447	  // reference of "onParamChange" changes on each re-render, hence storing in a "useRef"
 448	  onParamChangeRef.current = onParamChange;
 449	
 450	  const launchModal = useModal();
 451	
 452	  const [cephClusters, cephClustersLoaded, cephClustersLoadError] =
 453	    useK8sWatchResource<CephClusterKind[]>(cephClusterResource);
 454	
 455	  const [isOpen, setOpen] = React.useState(false);
 456	  const [poolName, setPoolName] = React.useState('');
 457	  const [systemNamespace, setSystemNamespace] = React.useState<string>();
 458	
 459	  const cephCluster = getResourceInNs(cephClusters, systemNamespace);
 460	
 461	  const { systemFlags, areFlagsLoaded, flagsLoadError, areFlagsSafe } =
 462	    useODFSystemFlagsSelector();
 463	  const isExternal = systemFlags[systemNamespace]?.isExternalMode;
 464	
 465	  const poolNs = getNamespace(cephCluster);
 466	  const clusterName = systemFlags[poolNs]?.ocsClusterName;
 467	  const defaultPoolName = `${clusterName}-cephblockpool`;
 468	  const [poolsData, poolDataLoaded, poolDataLoadError] = useK8sWatchResource<
 469	    StoragePoolKind[]
 470	  >(getCephBlockPoolResource(clusterName));
 471	  const filteredPools = poolsData?.filter(
 472	    (pool) => getNamespace(pool) === systemNamespace
 473	  );
 474	
 475	  // Collect existing pool names to check against new pool name.
 476	  const poolData = getStoragePoolsFromBlockPools(filteredPools) || [];
 477	  const existingNames = getExistingBlockPoolNames(poolData);
 478	
 479	  // Get the default deviceClass required by the 'create' modal.
 480	  const defaultPool = filteredPools.find(
 481	    (pool: StoragePoolKind) => pool.metadata.name === defaultPoolName
 482	  );
 483	  const defaultDeviceClass = defaultPool?.spec?.deviceClass || '';
 484	
 485	  const handleDropdownChange = (e: React.KeyboardEvent<HTMLInputElement>) => {
 486	    setPoolName(e.currentTarget.id);
 487	    onParamChange(parameterKey, e.currentTarget.id, false);
 488	  };
 489	
 490	  const onPoolCreation = (name: string) => {
 491	    setPoolName(name);
 492	    onParamChange(parameterKey, name, false);
 493	  };
 494	
 495	  const onPoolInput = (e: React.ChangeEvent<HTMLInputElement>) => {
 496	    setPoolName(e.currentTarget.value);
 497	    onParamChange(parameterKey, e.currentTarget.value, false);
 498	  };
 499	
 500	  const onSelect = React.useCallback(
 501	    (resource: K8sResourceKind) => {
 502	      const ns = getNamespace(resource);
 503	      sessionStorage.setItem(CEPH_NS_SESSION_STORAGE, ns);
 504	      setSystemNamespace(ns);
 505	      setPoolName('');
 506	      onParamChangeRef.current(parameterKey, '', false);
 507	    },
 508	    [setSystemNamespace, setPoolName, parameterKey]
 509	  );
 510	
 511	  setSessionStorageSystemNamespace(systemNamespace);
 512	
 513	  const blockPoolToggle = (toggleRef: React.Ref<MenuToggleElement>) => (
 514	    <MenuToggle
 515	      ref={toggleRef}
 516	      id="pool-dropdown-id"
 517	      data-test="pool-dropdown-toggle"
 518	      onClick={() => setOpen(!isOpen)}
 519	      isExpanded={isOpen}
 520	      isFullWidth
 521	    >
 522	      {poolName || t('Select a Pool')}
 523	    </MenuToggle>
 524	  );
 525	
 526	  if (areFlagsSafe && !isExternal) {
 527	    return (
 528	      <>
 529	        {!poolDataLoadError && !flagsLoadError && (
 530	          <>
 531	            <StorageSystemDropdown
 532	              onSelect={onSelect}
 533	              systemNamespace={systemNamespace}
 534	            />
 535	            <div className="form-group">
 536	              <label className="co-required" htmlFor="ocs-storage-pool">
 537	                {t('Storage Pool')}
 538	              </label>
 539	              <Dropdown
 540	                isOpen={isOpen}
 541	                onSelect={() => setOpen(false)}
 542	                onOpenChange={(open: boolean) => setOpen(open)}
 543	                toggle={blockPoolToggle}
 544	                popperProps={{ width: 'trigger' }}
 545	              >
 546	                <DropdownList>
 547	                  {getPoolDropdownItems(
 548	                    poolData,
 549	                    cephCluster,
 550	                    handleDropdownChange,
 551	                    onPoolCreation,
 552	                    launchModal,
 553	                    t,
 554	                    defaultDeviceClass,
 555	                    PoolType.BLOCK,
 556	                    existingNames
 557	                  )}
 558	                </DropdownList>
 559	              </Dropdown>
 560	              <span className="help-block">
 561	                {t('Storage pool into which volume data shall be stored')}
 562	              </span>
 563	            </div>
 564	          </>
 565	        )}
 566	        {(poolDataLoadError || cephClustersLoadError || flagsLoadError) && (
 567	          <Alert
 568	            className="co-alert"
 569	            variant="danger"
 570	            title={t('Error retrieving parameters')}
 571	            isInline
 572	          />
 573	        )}
 574	      </>
 575	    );
 576	  }
 577	  if (areFlagsSafe && isExternal) {
 578	    return (
 579	      <>
 580	        <StorageSystemDropdown
 581	          onSelect={onSelect}
 582	          systemNamespace={systemNamespace}
 583	        />
 584	        <div className="form-group">
 585	          <label className="co-required" htmlFor="pool-name">
 586	            {t('Storage Pool')}
 587	          </label>
 588	          <input
 589	            className="pf-v6-c-form-control"
 590	            type="text"
 591	            onChange={onPoolInput}
 592	            value={poolName}
 593	            placeholder={t('my-storage-pool')}
 594	            aria-describedby={t('pool-name-help')}
 595	            id="pool-name"
 596	            name="newPoolName"
 597	            required
 598	          />
 599	          <span className="help-block">
 600	            {t('Storage pool into which volume data shall be stored')}
 601	          </span>
 602	        </div>
 603	      </>
 604	    );
 605	  }
 606	  return (
 607	    <StatusBox
 608	      loadError={cephClustersLoadError || poolDataLoadError || flagsLoadError}
 609	      loaded={cephClustersLoaded && poolDataLoaded && areFlagsLoaded}
 610	    />
 611	  );
 612	};
