 614	const StorageClassEncryptionLabel: React.FC = () => {
 615	  const { t } = useCustomTranslation();
 616	
 617	  return (
 618	    <div className="ocs-storage-class-encryption__pv-title">
 619	      <span className="ocs-storage-class-encryption__pv-title--padding">
 620	        {t('Enable Encryption')}
 621	      </span>
 622	    </div>
