 626	export const StorageClassEncryption: React.FC<ProvisionerProps> = ({
 627	  parameterKey,
 628	  onParamChange,
 629	}) => {
 630	  const { t } = useCustomTranslation();
 631	
 632	  const [checked, isChecked] = React.useState(false);
 633	
 634	  const setChecked = (value: boolean) => {
 635	    onParamChange(parameterKey, value.toString(), false);
 636	    isChecked(value);
 637	  };
 638	
 639	  return (
 640	    <div className="ocs-storage-class__form">
 641	      <Form>
 642	        {/* Add form validation again */}
 643	        <FormGroup fieldId="storage-class-encryption" isRequired>
 644	          <Checkbox
 645	            id="storage-class-encryption"
 646	            isChecked={checked}
 647	            data-checked-state={checked}
 648	            label={<StorageClassEncryptionLabel />}
 649	            aria-label={t('StorageClass encryption')}
 650	            onChange={(_event, checkedArg) => setChecked(checkedArg)}
 651	            className="ocs-storage-class-encryption__form-checkbox"
 652	            data-test="storage-class-encryption"
 653	          />
 654	          <span className="help-block">
 655	            {t(
 656	              'An encryption key will be generated for each PersistentVolume created using this StorageClass.'
 657	            )}
 658	          </span>
 659	        </FormGroup>
 660	      </Form>
 661	    </div>
 662	  );
 663	};
 664	
 665	const ExistingKMSDropDown: React.FC<ExistingKMSDropDownProps> = ({
 666	  csiConfigMap,
 667	  serviceName,
 668	  kmsProvider,
 669	  infraType,
 670	  secrets,
 671	  setEncryptionId,
 672	}) => {
