 791	
 792	  return (
 793	    <div className="ocs-storage-class-encryption__form-dropdown--padding">
 794	      <div className="form-group">
 795	        <label htmlFor="kms-provider">{t('Provider')}</label>
 796	        <Dropdown
 797	          isOpen={isProviderOpen}
 798	          onSelect={() => setProviderOpen(false)}
 799	          onOpenChange={(open: boolean) => setProviderOpen(open)}
 800	          toggle={providerToggle}
 801	          popperProps={{ width: 'trigger' }}
