 822	const csiCMWatchResource: K8sResourceObj = (ns: string) => ({
 823	  kind: ConfigMapModel.kind,
 824	  namespaced: true,
 825	  isList: false,
 826	  namespace: ns,
 827	  name: KMSConfigMapCSIName,
 828	});
 829	
 830	const secretResource: K8sResourceObj = (ns: string) => ({
 831	  isList: true,
 832	  kind: SecretModel.kind,
 833	  namespace: ns,
 834	});
 835	
 836	export const StorageClassEncryptionKMSID: React.FC<ProvisionerProps> = ({
 837	  parameterKey,
 838	  onParamChange,
 839	}) => {
 840	  const { t } = useCustomTranslation();
 841	  const onParamChangeRef = React.useRef<OnParamChange>();
 842	  // reference of "onParamChange" changes on each re-render, hence storing in a "useRef"
 843	  onParamChangeRef.current = onParamChange;
 844	
 845	  const { odfNamespace, isODFNsLoaded, odfNsLoadError } =
 846	    useODFNamespaceSelector();
 847	
 848	  const [state, dispatch] = React.useReducer(reducer, initialState);
 849	  const [isExistingKms, setIsExistingKms] = React.useState<boolean>(true);
 850	  const [errorMessage, setErrorMessage] = React.useState<string>('');
 851	  const [progress, setInProgress] = React.useState<boolean>(false);
 852	  const [serviceName, setServiceName] = React.useState<string>('');
 853	
 854	  const { kms, encryption } = state.securityAndNetwork;
 855	  const { provider } = kms;
 856	
 857	  if (!encryption.storageClass) {
 858	    dispatch({
 859	      type: 'securityAndNetwork/setEncryption',
 860	      payload: {
 861	        ...encryption,
 862	        storageClass: true,
 863	      },
 864	    });
 865	  }
 866	
 867	  const [infra, infraLoaded, infraLoadError] = useK8sGet<InfrastructureKind>(
 868	    InfrastructureModel,
 869	    DEFAULT_INFRASTRUCTURE
 870	  );
 871	  const [csiConfigMap, csiConfigMapLoaded, csiConfigMapLoadError] =
 872	    useSafeK8sWatchResource<ConfigMapKind>(csiCMWatchResource);
 873	  const [secrets, secretsLoaded, secretsLoadError] =
 874	    useSafeK8sWatchResource<SecretKind[]>(secretResource);
 875	
 876	  const infraType = getInfrastructurePlatform(infra);
 877	  const memoizedCsiConfigMap = useDeepCompareMemoize(csiConfigMap, true);
 878	
 879	  const setEncryptionId = React.useCallback(
 880	    (encryptionId: string) => {
 881	      setServiceName(encryptionId);
 882	      onParamChangeRef.current(parameterKey, encryptionId, false);
 883	    },
 884	    [parameterKey]
 885	  );
 886	
 887	  /** When csiConfigMap is deleted from another tab, "csiConfigMapLoadError" == true (404 Not Found), but,
 888	   * "csiConfigMap" still contains same old object that was present before the deletion of the configMap.
 889	   * Hence, dropdown was not updating dynamically. Used "csiKmsDetails" to handle that.
 890	   */
 891	  const [csiKmsDetails, setCsiKmsDetails] = React.useState<ConfigMapKind>(null);
 892	  React.useEffect(() => {
 893	    if (csiConfigMapLoaded && !csiConfigMapLoadError && memoizedCsiConfigMap) {
 894	      setCsiKmsDetails(memoizedCsiConfigMap);
 895	    } else if (csiConfigMapLoadError) {
 896	      setIsExistingKms(false);
 897	      setCsiKmsDetails(null);
 898	      setEncryptionId('');
 899	    }
 900	  }, [
 901	    memoizedCsiConfigMap,
 902	    csiConfigMapLoaded,
 903	    csiConfigMapLoadError,
 904	    setIsExistingKms,
 905	    setEncryptionId,
 906	  ]);
 907	
 908	  const updateKMS = async () => {
 909	    setInProgress(true);
 910	    const allServiceNames = csiKmsDetails
 911	      ? Object.keys(csiKmsDetails?.data)
 912	      : [];
 913	    if (
 914	      (allServiceNames.length &&
 915	        allServiceNames.indexOf(kms.providerState.name.value) === -1) ||
 916	      !csiKmsDetails
 917	    ) {
 918	      try {
 919	        const promises: Promise<K8sResourceKind>[] = createCsiKmsResources(
 920	          kms.providerState,
 921	          !!csiKmsDetails,
 922	          odfNamespace,
 923	          provider
 924	        );
 925	        await Promise.all(promises).then(() => {
 926	          setIsExistingKms(true);
 927	          setEncryptionId(kms.providerState.name.value);
 928	        });
 929	        setErrorMessage('');
 930	      } catch (error) {
 931	        setErrorMessage(error.message);
 932	      }
 933	    } else {
 934	      setErrorMessage(
 935	        t('KMS service {{value}} already exist', {
 936	          value: kms.providerState.name.value,
 937	        })
 938	      );
 939	    }
 940	    setInProgress(false);
 941	  };
 942	
 943	  if (
 944	    (!csiConfigMapLoaded && !csiConfigMapLoadError) ||
 945	    !infraLoaded ||
 946	    infraLoadError ||
 947	    !secretsLoaded ||
 948	    secretsLoadError ||
 949	    !isODFNsLoaded ||
 950	    odfNsLoadError
 951	  ) {
 952	    return (
 953	      <StatusBox
 954	        loadError={
 955	          infraLoadError ||
 956	          (!isNotFoundError(csiConfigMapLoadError) && csiConfigMapLoadError) ||
 957	          secretsLoadError ||
 958	          odfNsLoadError
 959	        }
 960	        loaded={
 961	          infraLoaded && csiConfigMapLoaded && secretsLoaded && isODFNsLoaded
 962	        }
 963	      />
 964	    );
 965	  }
 966	  return (
 967	    <Form className="ocs-storage-class-encryption__form--padding">
 968	      <FormGroup fieldId="rbd-sc-kms-connection-selector">
 969	        <div id="rbd-sc-kms-connection-selector">
 970	          <Radio
 971	            label={t('Choose existing KMS connection')}
 972	            name="kms-selection"
 973	            id="choose-existing-kms-connection"
 974	            className="ocs-storage-class-encryption__form-radio"
 975	            onClick={() => setIsExistingKms(true)}
 976	            checked={isExistingKms}
 977	          />
 978	          {isExistingKms && (
 979	            <ExistingKMSDropDown
 980	              csiConfigMap={csiKmsDetails}
 981	              serviceName={serviceName}
 982	              kmsProvider={provider}
 983	              infraType={infraType}
 984	              secrets={secrets}
 985	              setEncryptionId={setEncryptionId}
 986	            />
 987	          )}
 988	          <Radio
 989	            label={t('Create new KMS connection')}
 990	            name="kms-selection"
 991	            id="create-new-kms-connection"
 992	            className="ocs-storage-class-encryption__form-radio"
 993	            onClick={() => setIsExistingKms(false)}
 994	            checked={!isExistingKms}
 995	            data-test={`sc-form-new-kms-radio`}
 996	          />
 997	          {!isExistingKms && (
 998	            <Card className="ocs-storage-class-encryption__card">
 999	              <KMSConfigure
1000	                state={state.securityAndNetwork}
1001	                dispatch={dispatch}
1002	                infraType={infraType}
1003	                systemNamespace={odfNamespace}
1004	                className="ocs-storage-class-encryption"
1005	              />
1006	              <div className="ocs-install-kms__save-button">
1007	                <ButtonBar errorMessage={errorMessage} inProgress={progress}>
1008	                  <ActionGroup>
1009	                    <Button
1010	                      variant="secondary"
1011	                      onClick={updateKMS}
1012	                      isDisabled={!kms.providerState.hasHandled}
1013	                      data-test="save-action"
1014	                    >
1015	                      {t('Save')}
1016	                    </Button>
1017	                  </ActionGroup>
1018	                </ButtonBar>
1019	              </div>
1020	            </Card>
1021	          )}
1022	        </div>
1023	      </FormGroup>
1024	    </Form>
1025	  );
1026	};
